mapper.select:
SELECT 
FROM ds_withdraw_request
WHERE customer_no = #{customerNo}

  AND status = #{status}


  AND withdraw_type = #{withdrawType}

ORDER BY create_time DESC, id DESC

SELECT 
FROM ds_withdraw_request
WHERE create_time BETWEEN #{startTime} AND #{endTime}

  AND customer_no = #{customerNo}


  AND status = #{status}


  AND withdraw_type = #{withdrawType}

ORDER BY create_time DESC, id DESC

choose.when:
SELECT status, COUNT(*) as id, SUM(amount) as amount,
       SUM(fee_amount) as feeAmount, SUM(actual_amount) as actualAmount
FROM ds_withdraw_request
WHERE 1=1

  AND create_time >= #{startTime}


  AND create_time <= #{endTime}


  AND customer_no = #{customerNo}

GROUP BY status
ORDER BY status

SELECT withdraw_type as withdrawType, COUNT(*) as id, SUM(amount) as amount,
       SUM(fee_amount) as feeAmount, SUM(actual_amount) as actualAmount
FROM ds_withdraw_request
WHERE 1=1

  AND create_time >= #{startTime}


  AND create_time <= #{endTime}


  AND customer_no = #{customerNo}

GROUP BY withdraw_type
ORDER BY withdraw_type

choose.otherwise:
SELECT status, COUNT(*) as id, SUM(amount) as amount,
       SUM(fee_amount) as feeAmount, SUM(actual_amount) as actualAmount
FROM ds_withdraw_request
WHERE 1=1

  AND create_time >= #{startTime}


  AND create_time <= #{endTime}


  AND customer_no = #{customerNo}

GROUP BY status
ORDER BY status

mapper.select:
SELECT COUNT(*)
FROM ds_withdraw_request
WHERE request_no = #{requestNo}

SELECT t.*
FROM ds_withdraw_request t


        AND t.request_no LIKE CONCAT('%', #{requestNo}, '%')


        AND t.customer_no = #{customerNo}


        AND t.status = #{status}


        AND t.withdraw_type = #{withdrawType}


        AND t.create_time >= #{startTime}


        AND t.create_time <= #{endTime}


ORDER BY t.create_time DESC
